onMounted(() => {
  map = L.map(mapContainer.value, {
    zoomControl: true,
    scrollWheelZoom: false,
  })

  L.tileLayer('https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png', {
    attribution: '&copy; OpenStreetMap &copy; CartoDB',
    maxZoom: 19,
  }).addTo(map)

  // Draw track with elevation gradient
  const minEle = Math.min(...trackPoints.map(p => p[2]))
  const maxEle = Math.max(...trackPoints.map(p => p[2]))

  for (let i = 0; i < trackPoints.length - 1; i++) {
    const t = (trackPoints[i][2] - minEle) / (maxEle - minEle)
    const r = Math.round(t < 0.5 ? t * 2 * 200 : 200 + (t - 0.5) * 2 * 55)
    const g = Math.round(t < 0.5 ? 210 - t * 2 * 60 : 150 - (t - 0.5) * 2 * 150)
    const b = Math.round(t < 0.5 ? 100 - t * 2 * 100 : 0)
    const color = `rgb(${r},${g},${b})`

    L.polyline([
      [trackPoints[i][0], trackPoints[i][1]],
      [trackPoints[i+1][0], trackPoints[i+1][1]]
    ], { color, weight: 3, opacity: 0.9 }).addTo(map)
  }

  // Add checkpoint markers
  checkpointCoords.forEach((cp, idx) => {
    const color = cp.type === 'start' ? '#f59e0b' :
                  cp.type === 'finish' ? '#f59e0b' :
                  cp.type === 'full' ? '#10b981' : '#3b82f6'

    const icon = L.divIcon({
      html: `<div style="
        background:${color};
        color:#000;
        width:28px;height:28px;
        border-radius:50%;
        display:flex;align-items:center;justify-content:center;
        font-weight:bold;font-size:11px;
        border:2px solid white;
        box-shadow:0 2px 6px rgba(0,0,0,0.5);
      ">${idx === 0 ? '🚀' : idx === checkpointCoords.length - 1 ? '🏁' : idx}</div>`,
      className: '',
      iconSize: [28, 28],
      iconAnchor: [14, 14],
    })

    const ravito = cp.type === 'full' ? '🟢 Ravito complet' :
                   cp.type === 'water' ? '🔵 Eau seulement' :
                   cp.type === 'start' ? '🚀 Départ' : '🏁 Arrivée'

    const keyBadge = cp.key ? '<br><span style="color:#f59e0b;font-weight:bold">⚠️ Ravito clé</span>' : ''

    L.marker([cp.lat, cp.lon], { icon })
      .addTo(map)
      .bindPopup(`
        <div style="font-family:sans-serif;min-width:160px">
          <strong style="font-size:13px">${cp.name}</strong><br>
          <span style="color:#666">km ${cp.km} · D+ ${cp.dplus}m</span><br>
          <span style="color:#10b981;font-weight:bold">⏱ ${cp.targetTime}</span><br>
          ${ravito}${keyBadge}
        </div>
      `, { maxWidth: 200 })
  })

  // Fit map to track bounds
  const bounds = L.latLngBounds(trackPoints.map(p => [p[0], p[1]]))
  map.fitBounds(bounds, { padding: [20, 20] })
})

onUnmounted(() => {
  if (map) { map.remove(); map = null }
})
</script>
